#include <iostream>
#include <string>
#include <vector>
#include <cstdlib>
#include <ctime>
#include <cmath>
#include <sys/socket.h>
#include <arpa/inet.h>
#include <netinet/in.h>
#include <unistd.h>

using namespace std;

const int PORT = 8080;
const int MAX_PLAYERS = 10;
const int MAX_BUFFER_SIZE = 1024;

struct Player {
    string name;
    double x, y, z;
};

vector<Player> players;

void handlePacket(char* buffer) {
    // Parse the packet and update player position
    int playerId = atoi(buffer);
    if (playerId >= 0 && playerId < MAX_PLAYERS) {
        Player& player = players[playerId];
        string action = buffer + sizeof(int);
        if (action == "move") {
            // Update player position based on movement data
            double x = atof(buffer + 2 * sizeof(int));
            double y = atof(buffer + 3 * sizeof(int));
            double z = atof(buffer + 4 * sizeof(int));
            player.x += x;
            player.y += y;
            player.z += z;
        } else if (action == "shoot") {
            // Handle shooting mechanics
            cout << "Player " << playerId << " has shot!" << endl;
        }
    }
}

int main() {
    // Initialize UDP socket
    int sock = socket(AF_INET, SOCK_DGRAM, 0);
    if (sock < 0) {
        perror("socket failed");
        exit(1);
    }

    // Bind to port
    struct sockaddr_in serverAddr;
    memset(&serverAddr, 0, sizeof(serverAddr));
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_port = htons(PORT);
    if (bind(sock, (struct sockaddr*)&serverAddr, sizeof(serverAddr)) < 0) {
        perror("bind failed");
        exit(1);
    }

    // Listen for incoming packets
    while (true) {
        char buffer[MAX_BUFFER_SIZE];
        struct sockaddr_in clientAddr;
        int addrLen = sizeof(clientAddr);
        if (recvfrom(sock, buffer, MAX_BUFFER_SIZE, 0, (struct sockaddr*)&clientAddr, &addrLen) < 0) {
            perror("recvfrom failed");
            exit(1);
        }
        handlePacket(buffer);
    }

    return 0;
}